var documenterSearchIndex = {"docs":
[{"location":"guide/export/#Export","page":"Export","title":"Export","text":"This guide covers how to export dynamic network animations from NDTV.jl to various formats including HTML, video, and GIF.","category":"section"},{"location":"guide/export/#Overview","page":"Export","title":"Overview","text":"After computing a layout with render_animation or layout_sequence, you can export the result in several formats:\n\nFormat Function Requirements Interactive?\nHTML export_html None Yes\nVideo (MP4) export_movie FFmpeg No\nGIF export_gif ImageMagick No","category":"section"},{"location":"guide/export/#Export-Workflow","page":"Export","title":"Export Workflow","text":"The typical export workflow is:\n\nusing NetworkDynamic\nusing NDTV\n\n# 1. Create and populate your dynamic network\ndnet = DynamicNetwork(10; observation_start=0.0, observation_end=100.0)\nfor i in 1:10\n    activate!(dnet, 0.0, 100.0; vertex=i)\nend\nactivate!(dnet, 0.0, 50.0; edge=(1, 2))\nactivate!(dnet, 25.0, 75.0; edge=(2, 3))\nactivate!(dnet, 50.0, 100.0; edge=(3, 4))\n\n# 2. Compute the animation layout\nlayout = render_animation(dnet;\n    algorithm=FRLayout(),\n    n_frames=100\n)\n\n# 3. Export to your desired format\nexport_html(layout, \"animation.html\")","category":"section"},{"location":"guide/export/#HTML-Export","page":"Export","title":"HTML Export","text":"HTML export creates a self-contained HTML file with an embedded animation viewer. This is the recommended format for sharing and presentation because it requires no external software.","category":"section"},{"location":"guide/export/#Basic-Usage","page":"Export","title":"Basic Usage","text":"export_html(layout, \"my_animation.html\")","category":"section"},{"location":"guide/export/#Configuration","page":"Export","title":"Configuration","text":"Use HTMLConfig to customize the output:\n\nconfig = HTMLConfig(\n    width=800,       # Canvas width in pixels\n    height=600,      # Canvas height in pixels\n    controls=true    # Show playback controls\n)\n\nexport_html(layout, \"my_animation.html\"; config=config)","category":"section"},{"location":"guide/export/#Parameters","page":"Export","title":"Parameters","text":"Parameter Type Default Description\nwidth Int 800 Canvas width in pixels\nheight Int 600 Canvas height in pixels\ncontrols Bool true Show play/pause/scrub controls","category":"section"},{"location":"guide/export/#Output-Details","page":"Export","title":"Output Details","text":"The generated HTML file contains:\n\nA <canvas> element for rendering the network\nFrame data embedded as JSON\nJavaScript for animation playback\nTime range information (start to end)\n\nresult = export_html(layout, \"output.html\")\nprintln(result.filepath)    # \"output.html\"\nprintln(result.n_frames)    # Number of frames in the animation","category":"section"},{"location":"guide/export/#When-to-Use-HTML","page":"Export","title":"When to Use HTML","text":"Presentations: Interactive playback in any web browser\nSharing: Single file, no dependencies required to view\nExploration: Scrub through time points interactively\nWeb integration: Embed in websites or Jupyter notebooks","category":"section"},{"location":"guide/export/#Video-Export","page":"Export","title":"Video Export","text":"Video export creates an MP4 (or other codec) video file using FFmpeg. This produces a fixed-framerate video suitable for embedding in presentations or publications.","category":"section"},{"location":"guide/export/#Requirements","page":"Export","title":"Requirements","text":"Video export requires FFmpeg to be installed and available on your system PATH:\n\n# Ubuntu/Debian\nsudo apt install ffmpeg\n\n# macOS with Homebrew\nbrew install ffmpeg\n\n# Verify installation\nffmpeg -version","category":"section"},{"location":"guide/export/#Basic-Usage-2","page":"Export","title":"Basic Usage","text":"export_movie(layout, \"my_animation.mp4\")","category":"section"},{"location":"guide/export/#Configuration-2","page":"Export","title":"Configuration","text":"Use VideoConfig to customize the output:\n\nconfig = VideoConfig(\n    fps=30,           # Frames per second\n    width=800,        # Video width in pixels\n    height=600,       # Video height in pixels\n    codec=\"h264\"      # Video codec\n)\n\nexport_movie(layout, \"my_animation.mp4\"; config=config)","category":"section"},{"location":"guide/export/#Parameters-2","page":"Export","title":"Parameters","text":"Parameter Type Default Description\nfps Int 30 Frames per second\nwidth Int 800 Video width in pixels\nheight Int 600 Video height in pixels\ncodec String \"h264\" Video codec (h264, h265, vp9)","category":"section"},{"location":"guide/export/#Choosing-FPS-and-Frame-Count","page":"Export","title":"Choosing FPS and Frame Count","text":"The total animation duration depends on both the number of frames and the FPS:\n\nduration = n_frames / fps\n\nn_frames FPS Duration\n100 30 3.3 seconds\n100 10 10 seconds\n300 30 10 seconds\n600 30 20 seconds\n\n# 10-second animation at 30 fps\nlayout = render_animation(dnet; n_frames=300)\nexport_movie(layout, \"animation.mp4\";\n    config=VideoConfig(fps=30)\n)","category":"section"},{"location":"guide/export/#When-to-Use-Video","page":"Export","title":"When to Use Video","text":"Publications: Embed in supplementary materials\nPresentations: Fixed playback, no interaction needed\nSocial media: Widely supported format\nLarge audiences: Guaranteed playback without browser requirements","category":"section"},{"location":"guide/export/#GIF-Export","page":"Export","title":"GIF Export","text":"GIF export creates an animated GIF using ImageMagick. GIFs are widely supported but have lower quality than video and larger file sizes.","category":"section"},{"location":"guide/export/#Requirements-2","page":"Export","title":"Requirements","text":"GIF export requires ImageMagick to be installed:\n\n# Ubuntu/Debian\nsudo apt install imagemagick\n\n# macOS with Homebrew\nbrew install imagemagick\n\n# Verify installation\nconvert --version","category":"section"},{"location":"guide/export/#Basic-Usage-3","page":"Export","title":"Basic Usage","text":"export_gif(layout, \"my_animation.gif\")","category":"section"},{"location":"guide/export/#Configuration-3","page":"Export","title":"Configuration","text":"Use GIFConfig to customize the output:\n\nconfig = GIFConfig(\n    fps=10,           # Frames per second (lower for smaller files)\n    width=400,        # GIF width in pixels\n    height=400,       # GIF height in pixels\n    loop=0            # Loop count (0 = infinite)\n)\n\nexport_gif(layout, \"my_animation.gif\"; config=config)","category":"section"},{"location":"guide/export/#Parameters-3","page":"Export","title":"Parameters","text":"Parameter Type Default Description\nfps Int 10 Frames per second\nwidth Int 400 GIF width in pixels\nheight Int 400 GIF height in pixels\nloop Int 0 Loop count (0 = infinite loop)","category":"section"},{"location":"guide/export/#GIF-Size-Optimization","page":"Export","title":"GIF Size Optimization","text":"GIFs can become very large. To keep file sizes manageable:\n\n# Reduce resolution\nconfig = GIFConfig(width=200, height=200, fps=5)\n\n# Use fewer frames\nlayout = render_animation(dnet; n_frames=30)\nexport_gif(layout, \"small.gif\"; config=config)","category":"section"},{"location":"guide/export/#When-to-Use-GIF","page":"Export","title":"When to Use GIF","text":"Documentation: Inline animations in README files\nMessaging: GIFs are supported in most chat platforms\nSimple animations: Short sequences with few frames\nPreviews: Quick visual summaries of network dynamics","category":"section"},{"location":"guide/export/#Export-Configuration-Types","page":"Export","title":"Export Configuration Types","text":"All export configurations subtype ExportConfig:\n\nabstract type ExportConfig end\n\nstruct VideoConfig <: ExportConfig ... end\nstruct GIFConfig <: ExportConfig ... end\nstruct HTMLConfig <: ExportConfig ... end","category":"section"},{"location":"guide/export/#Default-Configurations","page":"Export","title":"Default Configurations","text":"Each config type has sensible defaults:\n\n# All defaults\nVideoConfig()   # fps=30, 800x600, h264\nGIFConfig()     # fps=10, 400x400, loop=0\nHTMLConfig()    # 800x600, controls=true","category":"section"},{"location":"guide/export/#Format-Comparison","page":"Export","title":"Format Comparison","text":"Feature HTML Video GIF\nFile size Small Medium Large\nQuality High High Limited (256 colors)\nInteractive Yes No No\nDependencies None (to view) FFmpeg (to create) ImageMagick (to create)\nBrowser support Universal Requires player Universal\nBest resolution Any Up to 4K Under 600px","category":"section"},{"location":"guide/export/#Complete-Export-Example","page":"Export","title":"Complete Export Example","text":"using NetworkDynamic\nusing NDTV\n\n# Create a dynamic network\ndnet = DynamicNetwork(15; observation_start=0.0, observation_end=100.0)\n\nfor i in 1:15\n    activate!(dnet, 0.0, 100.0; vertex=i)\nend\n\n# Community 1 edges\nfor (i, j, t1, t2) in [(1,2,0,80), (1,3,0,80), (2,3,10,70)]\n    activate!(dnet, Float64(t1), Float64(t2); edge=(i, j))\nend\n\n# Community 2 edges\nfor (i, j, t1, t2) in [(4,5,20,100), (4,6,20,100), (5,6,30,90)]\n    activate!(dnet, Float64(t1), Float64(t2); edge=(i, j))\nend\n\n# Bridge edge connecting communities\nactivate!(dnet, 40.0, 60.0; edge=(3, 4))\n\n# Compute animation\nlayout = render_animation(dnet;\n    algorithm=FRLayout(iterations=150),\n    n_frames=150\n)\n\n# Export in all three formats\nexport_html(layout, \"communities.html\";\n    config=HTMLConfig(width=1024, height=768))\n\nexport_movie(layout, \"communities.mp4\";\n    config=VideoConfig(fps=30, width=1920, height=1080))\n\nexport_gif(layout, \"communities.gif\";\n    config=GIFConfig(fps=10, width=400, height=400))","category":"section"},{"location":"guide/export/#Return-Values","page":"Export","title":"Return Values","text":"All export functions return a named tuple with metadata:\n\n# HTML export\nresult = export_html(layout, \"out.html\")\nresult.filepath    # \"out.html\"\nresult.n_frames    # Number of frames\n\n# Video export\nresult = export_movie(layout, \"out.mp4\")\nresult.filepath    # \"out.mp4\"\nresult.n_frames    # Number of frames\nresult.fps         # Frames per second\n\n# GIF export\nresult = export_gif(layout, \"out.gif\")\nresult.filepath    # \"out.gif\"\nresult.n_frames    # Number of frames\nresult.fps         # Frames per second","category":"section"},{"location":"guide/export/#Troubleshooting","page":"Export","title":"Troubleshooting","text":"","category":"section"},{"location":"guide/export/#FFmpeg-Not-Found","page":"Export","title":"FFmpeg Not Found","text":"If export_movie warns about FFmpeg:\n\n# Check if FFmpeg is available\nrun(`ffmpeg -version`)\n\nInstall FFmpeg from ffmpeg.org or your system package manager.","category":"section"},{"location":"guide/export/#ImageMagick-Not-Found","page":"Export","title":"ImageMagick Not Found","text":"If export_gif warns about ImageMagick:\n\n# Check if ImageMagick is available\nrun(`convert --version`)\n\nInstall ImageMagick from imagemagick.org or your system package manager.","category":"section"},{"location":"guide/export/#Large-File-Sizes","page":"Export","title":"Large File Sizes","text":"If exported files are too large:\n\nReduce n_frames in render_animation\nLower resolution in the config (width, height)\nFor GIF: reduce fps and dimensions\nFor video: use a more efficient codec (\"h265\")","category":"section"},{"location":"guide/export/#Animation-Too-Fast-or-Slow","page":"Export","title":"Animation Too Fast or Slow","text":"Adjust the relationship between n_frames and fps:\n\n# Slow animation: many frames, low fps\nlayout = render_animation(dnet; n_frames=300)\nexport_movie(layout, \"slow.mp4\"; config=VideoConfig(fps=10))  # 30 seconds\n\n# Fast animation: fewer frames, high fps\nlayout = render_animation(dnet; n_frames=60)\nexport_movie(layout, \"fast.mp4\"; config=VideoConfig(fps=30))  # 2 seconds","category":"section"},{"location":"api/types/#Types-API-Reference","page":"Types","title":"Types API Reference","text":"This page documents the core data types in NDTV.jl.","category":"section"},{"location":"api/types/#Layout-Types","page":"Types","title":"Layout Types","text":"","category":"section"},{"location":"api/types/#Layout-Algorithm-Types","page":"Types","title":"Layout Algorithm Types","text":"","category":"section"},{"location":"api/types/#NDTV.DynamicLayout","page":"Types","title":"NDTV.DynamicLayout","text":"DynamicLayout{T}\n\nLayout positions for dynamic network visualization across time.\n\nFields\n\npositions::Vector{Dict{T, Tuple{Float64, Float64}}}: Position per vertex per time\ntimes::Vector{Float64}: Time points\nbounds::Tuple{Float64, Float64, Float64, Float64}: (xmin, xmax, ymin, ymax)\n\n\n\n\n\n","category":"type"},{"location":"api/types/#NDTV.InterpolatedLayout","page":"Types","title":"NDTV.InterpolatedLayout","text":"InterpolatedLayout{T}\n\nLayout with smooth interpolation between time points.\n\n\n\n\n\n","category":"type"},{"location":"api/types/#NDTV.FRLayout","page":"Types","title":"NDTV.FRLayout","text":"FRLayout\n\nFruchterman-Reingold force-directed layout parameters.\n\n\n\n\n\n","category":"type"},{"location":"api/types/#NDTV.KKLayout","page":"Types","title":"NDTV.KKLayout","text":"KKLayout\n\nKamada-Kawai layout parameters.\n\n\n\n\n\n","category":"type"},{"location":"api/types/#NDTV.CircleLayout","page":"Types","title":"NDTV.CircleLayout","text":"CircleLayout\n\nSimple circular layout.\n\n\n\n\n\n","category":"type"},{"location":"api/types/#NDTV.RandomLayout","page":"Types","title":"NDTV.RandomLayout","text":"RandomLayout\n\nRandom layout with specified bounds.\n\n\n\n\n\n","category":"type"},{"location":"getting_started/#Getting-Started","page":"Getting Started","title":"Getting Started","text":"This tutorial walks through common use cases for NDTV.jl, from basic animation to advanced visualization of dynamic networks.","category":"section"},{"location":"getting_started/#Installation","page":"Getting Started","title":"Installation","text":"Install NDTV.jl from GitHub:\n\nusing Pkg\nPkg.add(url=\"https://github.com/Statistical-network-analysis-with-Julia/NDTV.jl\")\n\nNDTV.jl depends on NetworkDynamic.jl for dynamic network data structures. Install it as well:\n\nPkg.add(url=\"https://github.com/Statistical-network-analysis-with-Julia/NetworkDynamic.jl\")","category":"section"},{"location":"getting_started/#Basic-Workflow","page":"Getting Started","title":"Basic Workflow","text":"The typical NDTV.jl workflow consists of four steps:\n\nCreate a dynamic network – Define vertices and edges with activity spells\nCompute layouts – Position vertices at each time point using layout algorithms\nVisualize – Generate timelines, filmstrips, or animation frames\nExport – Save results as HTML, video, or GIF","category":"section"},{"location":"getting_started/#Step-1:-Create-a-Dynamic-Network","page":"Getting Started","title":"Step 1: Create a Dynamic Network","text":"Dynamic networks are created using NetworkDynamic.jl. Vertices and edges have activity spells that define when they are present:\n\nusing NetworkDynamic\nusing NDTV\n\n# Create a dynamic network with 5 vertices observed from t=0 to t=100\ndnet = DynamicNetwork(5; observation_start=0.0, observation_end=100.0)\n\n# Activate all vertices for the full observation period\nfor i in 1:5\n    activate!(dnet, 0.0, 100.0; vertex=i)\nend\n\n# Add edge activity spells\n# Edge (1,2) is active from t=0 to t=40\nactivate!(dnet, 0.0, 40.0; edge=(1, 2))\n\n# Edge (2,3) is active from t=20 to t=70\nactivate!(dnet, 20.0, 70.0; edge=(2, 3))\n\n# Edge (3,4) is active from t=40 to t=90\nactivate!(dnet, 40.0, 90.0; edge=(3, 4))\n\n# Edge (4,5) is active from t=60 to t=100\nactivate!(dnet, 60.0, 100.0; edge=(4, 5))\n\n# Edge (1,3) appears temporarily from t=10 to t=30\nactivate!(dnet, 10.0, 30.0; edge=(1, 3))","category":"section"},{"location":"getting_started/#Understanding-Activity-Spells","page":"Getting Started","title":"Understanding Activity Spells","text":"Each vertex and edge can have multiple activity spells – intervals during which they are active. A vertex or edge can appear, disappear, and reappear:\n\n# Vertex 1 is active in two intervals\nactivate!(dnet, 0.0, 50.0; vertex=1)\nactivate!(dnet, 70.0, 100.0; vertex=1)\n\n# Edge (1,2) also has two spells\nactivate!(dnet, 0.0, 30.0; edge=(1, 2))\nactivate!(dnet, 60.0, 90.0; edge=(1, 2))","category":"section"},{"location":"getting_started/#Network-Snapshots","page":"Getting Started","title":"Network Snapshots","text":"At any time point, you can extract the active subnetwork:\n\n# Get the network at time t=25\nsnapshot = network_extract(dnet, 25.0)\nprintln(\"Vertices at t=25: \", nv(snapshot))\nprintln(\"Edges at t=25: \", ne(snapshot))","category":"section"},{"location":"getting_started/#Step-2:-Compute-Animation-Layout","page":"Getting Started","title":"Step 2: Compute Animation Layout","text":"NDTV.jl computes vertex positions for each time point using force-directed or geometric layout algorithms:\n\n# Compute animation with 50 frames using Fruchterman-Reingold layout\nlayout = render_animation(dnet;\n    algorithm=FRLayout(),\n    n_frames=50,\n    interpolation=:linear\n)\n\nprintln(\"Number of frames: \", length(layout))\nprintln(\"Time range: \", layout.times[1], \" to \", layout.times[end])\nprintln(\"Layout bounds: \", layout.bounds)\n\nThe result is a DynamicLayout containing vertex positions at each frame:\n\n# Access positions at frame 1\npositions_frame1 = layout[1]\n# Returns Dict{vertex_id => (x, y)}\n\n# Access the time for each frame\nlayout.times  # Vector of time points","category":"section"},{"location":"getting_started/#Anchored-Layouts","page":"Getting Started","title":"Anchored Layouts","text":"By default, NDTV.jl uses anchored layouts: each frame's layout computation starts from the previous frame's positions. This produces smooth transitions:\n\n# Compute layout sequence with anchoring (default)\ntimes = collect(0.0:10.0:100.0)\nlayout = layout_sequence(dnet, times;\n    algorithm=FRLayout(),\n    anchor=true   # Use previous positions as starting point\n)\n\n# Without anchoring -- each frame is computed independently\nlayout_unanchored = layout_sequence(dnet, times;\n    algorithm=FRLayout(),\n    anchor=false\n)\n\nWith anchoring enabled:\n\nPersistent vertices maintain stable positions across frames\nNew vertices appear near their connected neighbors\nLayout changes are gradual rather than abrupt","category":"section"},{"location":"getting_started/#Choosing-a-Layout-Algorithm","page":"Getting Started","title":"Choosing a Layout Algorithm","text":"NDTV.jl provides four layout algorithms:\n\n# Fruchterman-Reingold: Force-directed (best for most networks)\nfr = FRLayout(iterations=100, cooling=0.95, k=1.0)\n\n# Kamada-Kawai: Energy-based (good for small networks)\nkk = KKLayout(iterations=100, epsilon=1e-4)\n\n# Circle: Uniform circular placement\ncircle = CircleLayout(radius=1.0, start_angle=0.0)\n\n# Random: Random uniform placement\nrandom = RandomLayout(xmin=0.0, xmax=1.0, ymin=0.0, ymax=1.0)\n\nAlgorithm Best For Stability Speed\nFRLayout General networks High (with anchoring) Medium\nKKLayout Small networks (<50 vertices) High Slow\nCircleLayout Fixed-structure comparisons Perfect Fast\nRandomLayout Initial exploration None Fast","category":"section"},{"location":"getting_started/#Step-3:-Visualize-the-Network","page":"Getting Started","title":"Step 3: Visualize the Network","text":"","category":"section"},{"location":"getting_started/#Timeline-Plot","page":"Getting Started","title":"Timeline Plot","text":"The simplest visualization is an ASCII timeline showing when vertices and edges are active:\n\ntimeline_plot(dnet)\n\nThis produces output like:\n\nTimeline: 0.0 to 100.0\n============================================================\n\nVertices:\nV1: |────────────────────────────────────────────────────────────|\nV2: |────────────────────────────────────────────────────────────|\nV3: |────────────────────────────────────────────────────────────|\nV4: |────────────────────────────────────────────────────────────|\nV5: |────────────────────────────────────────────────────────────|\n\nEdges:\n1→2: |════════════════════════                                    |\n2→3: |            ════════════════════════════════                |\n3→4: |                        ════════════════════════════════    |\n4→5: |                                    ════════════════════════|\n\nYou can control the display width:\n\ntimeline_plot(dnet; width=80)","category":"section"},{"location":"getting_started/#Proximity-Timeline","page":"Getting Started","title":"Proximity Timeline","text":"View activity from a single vertex's perspective:\n\n# Show all edges involving vertex 2\nproximity_timeline(dnet, 2)\n\nOutput:\n\nProximity timeline for vertex 2\n============================================================\n→ V1: |════════════════════════                                    |\n→ V3: |            ════════════════════════════════                |","category":"section"},{"location":"getting_started/#Filmstrip","page":"Getting Started","title":"Filmstrip","text":"Generate data for multiple snapshots side-by-side:\n\n# Get network snapshots at 5 time points\ntimes = [0.0, 25.0, 50.0, 75.0, 100.0]\nframes = filmstrip(dnet, times; algorithm=FRLayout())\n\nfor frame in frames\n    println(\"t=$(frame.time): $(frame.n_vertices) vertices, $(frame.n_edges) edges\")\nend\n\nYou can also use slice_layout for evenly-spaced slices over an interval:\n\nframes = slice_layout(dnet, 0.0, 100.0; n_slices=5, algorithm=FRLayout())","category":"section"},{"location":"getting_started/#Transmission-Timeline","page":"Getting Started","title":"Transmission Timeline","text":"For visualizing diffusion or contagion events:\n\n# Define transmission events: (source, target, time)\ntransmissions = [\n    (1, 2, 5.0),    # Vertex 1 transmits to 2 at t=5\n    (2, 3, 15.0),   # Vertex 2 transmits to 3 at t=15\n    (2, 4, 20.0),   # Vertex 2 transmits to 4 at t=20\n    (3, 5, 30.0),   # Vertex 3 transmits to 5 at t=30\n]\n\ntransmissionTimeline(dnet, transmissions)\n\nOutput:\n\nTransmission Timeline\n============================================================\n1→2: |  *                                                        | t=5.0\n2→3: |        *                                                  | t=15.0\n2→4: |           *                                               | t=20.0\n3→5: |                 *                                         | t=30.0","category":"section"},{"location":"getting_started/#Step-4:-Export-the-Animation","page":"Getting Started","title":"Step 4: Export the Animation","text":"","category":"section"},{"location":"getting_started/#HTML-Export","page":"Getting Started","title":"HTML Export","text":"The simplest export format creates a self-contained HTML file:\n\nlayout = render_animation(dnet; n_frames=100)\n\nexport_html(layout, \"my_animation.html\";\n    config=HTMLConfig(width=800, height=600, controls=true)\n)","category":"section"},{"location":"getting_started/#Video-Export","page":"Getting Started","title":"Video Export","text":"Video export requires FFmpeg to be installed on your system:\n\nexport_movie(layout, \"my_animation.mp4\";\n    config=VideoConfig(fps=30, width=800, height=600, codec=\"h264\")\n)","category":"section"},{"location":"getting_started/#GIF-Export","page":"Getting Started","title":"GIF Export","text":"GIF export requires ImageMagick:\n\nexport_gif(layout, \"my_animation.gif\";\n    config=GIFConfig(fps=10, width=400, height=400, loop=0)\n)","category":"section"},{"location":"getting_started/#Interpolated-Layout","page":"Getting Started","title":"Interpolated Layout","text":"For smoother animation between computed frames, use interpolated layouts:\n\n# Compute base layout\nbase = layout_sequence(dnet, collect(0.0:20.0:100.0);\n    algorithm=FRLayout()\n)\n\n# Create interpolated layout with linear interpolation\ninterp_linear = InterpolatedLayout(base; interpolation=:linear)\n\n# Or with ease (smooth acceleration/deceleration)\ninterp_ease = InterpolatedLayout(base; interpolation=:ease)\n\n# Query any vertex position at any time\npos = get_position(interp_ease, 1, 35.0)\nprintln(\"Vertex 1 at t=35: x=$(pos[1]), y=$(pos[2])\")\n\nInterpolation modes:\n\nMode Formula Effect\n:linear p(t) = p_1 + alpha(p_2 - p_1) Constant velocity\n:ease Cubic ease-in-out Smooth acceleration and deceleration","category":"section"},{"location":"getting_started/#Complete-Example:-Epidemic-Visualization","page":"Getting Started","title":"Complete Example: Epidemic Visualization","text":"Here is a complete example combining multiple NDTV.jl features to visualize disease transmission through a contact network:\n\nusing NetworkDynamic\nusing NDTV\n\n# Create a contact network with 10 individuals\ndnet = DynamicNetwork(10; observation_start=0.0, observation_end=50.0)\n\n# Activate all individuals\nfor i in 1:10\n    activate!(dnet, 0.0, 50.0; vertex=i)\nend\n\n# Define contact patterns (edges)\ncontacts = [\n    (1, 2, 0.0, 50.0),   # Household contacts\n    (1, 3, 0.0, 50.0),\n    (2, 4, 5.0, 40.0),   # Workplace contacts\n    (3, 5, 5.0, 40.0),\n    (4, 6, 10.0, 35.0),\n    (5, 7, 10.0, 35.0),\n    (6, 8, 15.0, 30.0),\n    (7, 9, 15.0, 45.0),\n    (8, 10, 20.0, 50.0),\n]\n\nfor (i, j, t_start, t_end) in contacts\n    activate!(dnet, t_start, t_end; edge=(i, j))\nend\n\n# Show the full timeline\nprintln(\"=== Contact Timeline ===\")\ntimeline_plot(dnet)\n\n# Define transmission events\ntransmissions = [\n    (1, 2, 3.0),    # Index case infects household member\n    (1, 3, 5.0),\n    (2, 4, 12.0),   # Workplace transmission\n    (3, 5, 14.0),\n    (4, 6, 22.0),   # Second wave\n    (5, 7, 25.0),\n]\n\n# Show transmission timeline\nprintln(\"\\n=== Transmission Events ===\")\ntransmissionTimeline(dnet, transmissions)\n\n# Show proximity timeline for the index case\nprintln(\"\\n=== Index Case (Vertex 1) Contacts ===\")\nproximity_timeline(dnet, 1)\n\n# Compute animation layout\nlayout = render_animation(dnet; n_frames=100, algorithm=FRLayout())\n\n# Generate filmstrip at key time points\nframes = filmstrip(dnet, [0.0, 10.0, 20.0, 30.0, 40.0, 50.0])\nprintln(\"\\n=== Network Snapshots ===\")\nfor f in frames\n    println(\"t=$(f.time): $(f.n_vertices) vertices, $(f.n_edges) edges\")\nend\n\n# Export animation\nexport_html(layout, \"epidemic_animation.html\")","category":"section"},{"location":"getting_started/#Best-Practices","page":"Getting Started","title":"Best Practices","text":"Start with timeline plots: Use timeline_plot to understand your data before computing layouts\nUse anchored layouts: Always keep anchor=true (default) for smooth animation transitions\nChoose frames wisely: Start with 50 frames and increase only if transitions look choppy\nSeed for reproducibility: Use Random.seed!() before layout computation for consistent results\nMatch FPS to frames: Total duration = n_frames / fps – aim for 5-15 second animations\nExport to HTML first: HTML export requires no dependencies and allows interactive exploration","category":"section"},{"location":"getting_started/#Next-Steps","page":"Getting Started","title":"Next Steps","text":"Learn about Animation Layout algorithms and configuration\nExplore Layout Algorithms in detail\nRead about Export options and formats","category":"section"},{"location":"api/export/#Export-API-Reference","page":"Export","title":"Export API Reference","text":"This page documents the functions for exporting dynamic network animations to various formats.","category":"section"},{"location":"api/export/#Export-Functions","page":"Export","title":"Export Functions","text":"","category":"section"},{"location":"api/export/#Configuration-Types","page":"Export","title":"Configuration Types","text":"","category":"section"},{"location":"api/export/#NDTV.export_html","page":"Export","title":"NDTV.export_html","text":"export_html(layout::DynamicLayout, filepath::String; config=HTMLConfig())\n\nExport a dynamic network animation as a self-contained HTML file. No external dependencies required to view.\n\nReturns a named tuple with filepath and n_frames.\n\n\n\n\n\n","category":"function"},{"location":"api/export/#NDTV.export_movie","page":"Export","title":"NDTV.export_movie","text":"export_movie(layout::DynamicLayout, filepath::String; config=VideoConfig())\n\nExport a dynamic network animation as a video file. Requires FFmpeg.\n\nReturns a named tuple with filepath, n_frames, and fps.\n\n\n\n\n\n","category":"function"},{"location":"api/export/#NDTV.export_gif","page":"Export","title":"NDTV.export_gif","text":"export_gif(layout::DynamicLayout, filepath::String; config=GIFConfig())\n\nExport a dynamic network animation as an animated GIF. Requires ImageMagick.\n\nReturns a named tuple with filepath, n_frames, and fps.\n\n\n\n\n\n","category":"function"},{"location":"api/export/#NDTV.ExportConfig","page":"Export","title":"NDTV.ExportConfig","text":"ExportConfig\n\nAbstract base type for all export configuration types. Subtypes: VideoConfig, GIFConfig, HTMLConfig.\n\n\n\n\n\n","category":"type"},{"location":"api/export/#NDTV.VideoConfig","page":"Export","title":"NDTV.VideoConfig","text":"VideoConfig(; fps=30, width=800, height=600, codec=\"h264\")\n\nConfiguration for video (MP4) export. Requires FFmpeg.\n\nFields\n\nfps::Int: Frames per second\nwidth::Int: Video width in pixels\nheight::Int: Video height in pixels\ncodec::String: Video codec (e.g., \"h264\", \"h265\", \"vp9\")\n\n\n\n\n\n","category":"type"},{"location":"api/export/#NDTV.GIFConfig","page":"Export","title":"NDTV.GIFConfig","text":"GIFConfig(; fps=10, width=400, height=400, loop=0)\n\nConfiguration for GIF export. Requires ImageMagick.\n\nFields\n\nfps::Int: Frames per second\nwidth::Int: GIF width in pixels\nheight::Int: GIF height in pixels\nloop::Int: Loop count (0 = infinite)\n\n\n\n\n\n","category":"type"},{"location":"api/export/#NDTV.HTMLConfig","page":"Export","title":"NDTV.HTMLConfig","text":"HTMLConfig(; width=800, height=600, controls=true)\n\nConfiguration for HTML export. No external dependencies required.\n\nFields\n\nwidth::Int: Canvas width in pixels\nheight::Int: Canvas height in pixels\ncontrols::Bool: Show playback controls\n\n\n\n\n\n","category":"type"},{"location":"api/layout/#Layout-API-Reference","page":"Layout","title":"Layout API Reference","text":"This page documents the layout computation, timeline visualization, and filmstrip functions in NDTV.jl.","category":"section"},{"location":"api/layout/#Animation","page":"Layout","title":"Animation","text":"","category":"section"},{"location":"api/layout/#Layout-Computation","page":"Layout","title":"Layout Computation","text":"","category":"section"},{"location":"api/layout/#Timeline-Visualization","page":"Layout","title":"Timeline Visualization","text":"","category":"section"},{"location":"api/layout/#Filmstrip","page":"Layout","title":"Filmstrip","text":"","category":"section"},{"location":"api/layout/#NDTV.render_animation","page":"Layout","title":"NDTV.render_animation","text":"render_animation(dnet::DynamicNetwork; kwargs...) -> DynamicLayout\n\nCompute layout positions for animating a dynamic network.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.compute_animation_layout","page":"Layout","title":"NDTV.compute_animation_layout","text":"render_animation(dnet::DynamicNetwork; kwargs...) -> DynamicLayout\n\nCompute layout positions for animating a dynamic network.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.compute_slice_layout","page":"Layout","title":"NDTV.compute_slice_layout","text":"compute_slice_layout(dnet::DynamicNetwork, time; algorithm=FRLayout()) -> Dict\n\nCompute layout for a network snapshot at a specific time.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.layout_sequence","page":"Layout","title":"NDTV.layout_sequence","text":"layout_sequence(dnet::DynamicNetwork, times; algorithm=FRLayout(), anchor=true) -> DynamicLayout\n\nCompute layouts for a sequence of time points.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.compute_layout","page":"Layout","title":"NDTV.compute_layout","text":"compute_layout(net::Network, algorithm::FRLayout) -> Dict{Int, Tuple{Float64, Float64}}\n\nCompute Fruchterman-Reingold layout for a static network.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.get_position","page":"Layout","title":"NDTV.get_position","text":"get_position(layout::InterpolatedLayout, vertex, time) -> Tuple{Float64, Float64}\n\nGet interpolated position at any time point.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.timeline_plot","page":"Layout","title":"NDTV.timeline_plot","text":"timeline_plot(dnet::DynamicNetwork; kwargs...) -> Nothing\n\nCreate a timeline visualization of network dynamics (ASCII).\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.proximity_timeline","page":"Layout","title":"NDTV.proximity_timeline","text":"proximity_timeline(dnet::DynamicNetwork, vertex; kwargs...) -> Nothing\n\nCreate an ego-centric timeline.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.transmissionTimeline","page":"Layout","title":"NDTV.transmissionTimeline","text":"transmissionTimeline(dnet::DynamicNetwork, transmissions; kwargs...)\n\nCreate timeline showing transmission events.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.timeline_data","page":"Layout","title":"NDTV.timeline_data","text":"timeline_data(dnet::DynamicNetwork) -> NamedTuple\n\nExtract timeline data for visualization.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.filmstrip","page":"Layout","title":"NDTV.filmstrip","text":"filmstrip(dnet::DynamicNetwork, times; kwargs...) -> Vector\n\nGenerate data for filmstrip visualization.\n\n\n\n\n\n","category":"function"},{"location":"api/layout/#NDTV.slice_layout","page":"Layout","title":"NDTV.slice_layout","text":"slice_layout(dnet::DynamicNetwork, onset, terminus; n_slices=5) -> Vector\n\nCreate layouts for multiple time slices.\n\n\n\n\n\n","category":"function"},{"location":"guide/layout/#Layout-Algorithms","page":"Layout Algorithms","title":"Layout Algorithms","text":"This guide covers the layout algorithms available in NDTV.jl for positioning vertices in dynamic network visualizations.","category":"section"},{"location":"guide/layout/#Overview","page":"Layout Algorithms","title":"Overview","text":"Layout algorithms compute vertex positions – (x y) coordinates – for network visualizations. NDTV.jl provides four algorithms, each suited to different use cases:\n\nAlgorithm Type Complexity Best For\nFRLayout Force-directed O(n^2 cdot textiters) General networks\nKKLayout Energy-based O(n^2 cdot textiters) Small networks\nCircleLayout Geometric O(n) Fixed-structure comparisons\nRandomLayout Random O(n) Initial exploration","category":"section"},{"location":"guide/layout/#Fruchterman-Reingold-Layout","page":"Layout Algorithms","title":"Fruchterman-Reingold Layout","text":"The Fruchterman-Reingold (FR) algorithm is the default layout method and the most commonly used for network visualization. It treats the graph as a physical system of charged particles connected by springs.","category":"section"},{"location":"guide/layout/#Algorithm","page":"Layout Algorithms","title":"Algorithm","text":"The FR algorithm works by simulating forces between vertices:\n\nRepulsive forces push all vertex pairs apart (like charged particles):\n\nf_r(d) = frack^2d\n\nAttractive forces pull connected vertices together (like springs):\n\nf_a(d) = fracd^2k\n\nwhere d is the distance between two vertices and k = sqrttextarea  n is the optimal vertex spacing.\n\nSimulated annealing gradually reduces a temperature parameter that limits vertex movement, allowing the layout to settle into a stable configuration.","category":"section"},{"location":"guide/layout/#Usage","page":"Layout Algorithms","title":"Usage","text":"# Default parameters\nlayout = compute_slice_layout(dnet, 50.0; algorithm=FRLayout())\n\n# Custom parameters\nfr = FRLayout(\n    iterations=200,   # More iterations for better convergence\n    cooling=0.98,     # Slower cooling for more exploration\n    k=1.5             # Larger spacing between vertices\n)\nlayout = compute_slice_layout(dnet, 50.0; algorithm=fr)","category":"section"},{"location":"guide/layout/#Parameters","page":"Layout Algorithms","title":"Parameters","text":"Parameter Type Default Description\niterations Int 100 Number of simulation steps\ncooling Float64 0.95 Temperature reduction factor per iteration\nk Float64 1.0 Scaling factor for optimal vertex spacing","category":"section"},{"location":"guide/layout/#How-Parameters-Affect-Layout","page":"Layout Algorithms","title":"How Parameters Affect Layout","text":"Iterations: Controls convergence quality. Too few iterations produce messy layouts; too many waste computation.\n\n# Quick but rough\nFRLayout(iterations=30)\n\n# Standard quality\nFRLayout(iterations=100)\n\n# High quality (slow)\nFRLayout(iterations=300)\n\nCooling: Controls how quickly the system \"freezes.\" Higher values (closer to 1.0) allow more exploration but slower convergence.\n\n# Fast convergence, may get stuck in local minima\nFRLayout(cooling=0.85)\n\n# Balanced (default)\nFRLayout(cooling=0.95)\n\n# Slow convergence, better global structure\nFRLayout(cooling=0.99)\n\nk (spacing): Scales the optimal distance between vertices. Larger values spread the layout out.\n\n# Compact layout\nFRLayout(k=0.5)\n\n# Standard spacing\nFRLayout(k=1.0)\n\n# Spread out\nFRLayout(k=2.0)","category":"section"},{"location":"guide/layout/#Implementation-Details","page":"Layout Algorithms","title":"Implementation Details","text":"The NDTV.jl implementation:\n\nInitializes vertex positions randomly in -1 1 times -1 1\nComputes all pairwise repulsive forces: O(n^2) per iteration\nComputes attractive forces for each edge: O(m) per iteration\nLimits displacement by the current temperature: textdisp_textmax = texttemp\nClamps positions to -1 1 bounds\nReduces temperature by the cooling factor each iteration\n\nFor anchored layouts (used in animation sequences), the algorithm:\n\nStarts from previous frame positions (not random)\nUses half the temperature (05 instead of 10)\nRuns half the iterations\nThis preserves layout stability while allowing gradual adaptation","category":"section"},{"location":"guide/layout/#Kamada-Kawai-Layout","page":"Layout Algorithms","title":"Kamada-Kawai Layout","text":"The Kamada-Kawai (KK) algorithm minimizes an energy function based on graph-theoretic distances. It tries to make the Euclidean distance between any two vertices proportional to their shortest-path distance in the graph.","category":"section"},{"location":"guide/layout/#Algorithm-2","page":"Layout Algorithms","title":"Algorithm","text":"KK minimizes the stress energy:\n\nE = sum_ij k_ij left( p_i - p_j - d_ij right)^2\n\nwhere:\n\nd_ij\nis the graph-theoretic distance (shortest path length) between vertices i and j\nk_ij = 1d_ij^2\nis the spring constant (closer vertices are more strongly constrained)\np_i - p_j\nis the Euclidean distance between vertex positions","category":"section"},{"location":"guide/layout/#Usage-2","page":"Layout Algorithms","title":"Usage","text":"kk = KKLayout(\n    iterations=100,\n    epsilon=1e-4\n)\n\nlayout = compute_slice_layout(dnet, 50.0; algorithm=kk)","category":"section"},{"location":"guide/layout/#Parameters-2","page":"Layout Algorithms","title":"Parameters","text":"Parameter Type Default Description\niterations Int 100 Maximum number of optimization steps\nepsilon Float64 1e-4 Convergence threshold","category":"section"},{"location":"guide/layout/#When-to-Use-KK","page":"Layout Algorithms","title":"When to Use KK","text":"KK produces high-quality layouts that respect graph distances, but it is more expensive than FR for large networks. Use KK when:\n\nThe network has fewer than ~50 vertices\nYou want distances in the layout to reflect graph-theoretic distances\nThe network has a clear hierarchical or tree-like structure\nYou need reproducible, stable layouts\n\n# Small network with clear structure\nkk = KKLayout(iterations=200, epsilon=1e-5)\nlayout = render_animation(dnet; algorithm=kk, n_frames=50)","category":"section"},{"location":"guide/layout/#Circle-Layout","page":"Layout Algorithms","title":"Circle Layout","text":"The circle layout places all vertices evenly around a circle. This ignores network structure entirely but provides a stable reference layout.","category":"section"},{"location":"guide/layout/#Usage-3","page":"Layout Algorithms","title":"Usage","text":"# Default circle\ncircle = CircleLayout()\n\n# Custom radius and starting angle\ncircle = CircleLayout(\n    radius=2.0,        # Larger circle\n    start_angle=π/4    # Start from 45 degrees\n)\n\nlayout = compute_slice_layout(dnet, 50.0; algorithm=circle)","category":"section"},{"location":"guide/layout/#Parameters-3","page":"Layout Algorithms","title":"Parameters","text":"Parameter Type Default Description\nradius Float64 1.0 Circle radius\nstart_angle Float64 0.0 Angle (radians) for the first vertex","category":"section"},{"location":"guide/layout/#Vertex-Placement","page":"Layout Algorithms","title":"Vertex Placement","text":"Vertex i is placed at:\n\nx_i = r cosleft(theta_0 + frac2pi(i-1)nright) quad\ny_i = r sinleft(theta_0 + frac2pi(i-1)nright)\n\nwhere r is the radius, theta_0 is the start angle, and n is the number of vertices.","category":"section"},{"location":"guide/layout/#When-to-Use-Circle-Layout","page":"Layout Algorithms","title":"When to Use Circle Layout","text":"Comparing networks: Same vertex positions across different time points\nAdjacency visualization: Focus on edge patterns rather than spatial structure\nReference layout: A baseline for comparing with force-directed results\nAnimation stability: Perfectly stable positions (no layout drift)\n\n# Compare network structure at two time points using identical vertex positions\npos_early = compute_slice_layout(dnet, 10.0; algorithm=CircleLayout())\npos_late = compute_slice_layout(dnet, 90.0; algorithm=CircleLayout())\n# Only edges differ -- vertices are in the same positions","category":"section"},{"location":"guide/layout/#Random-Layout","page":"Layout Algorithms","title":"Random Layout","text":"The random layout places vertices uniformly at random within specified bounds. This is the fastest layout but provides no structural information.","category":"section"},{"location":"guide/layout/#Usage-4","page":"Layout Algorithms","title":"Usage","text":"# Default bounds [0, 1] x [0, 1]\nrandom = RandomLayout()\n\n# Custom bounds\nrandom = RandomLayout(\n    xmin=-2.0, xmax=2.0,\n    ymin=-2.0, ymax=2.0\n)\n\nlayout = compute_slice_layout(dnet, 50.0; algorithm=random)","category":"section"},{"location":"guide/layout/#Parameters-4","page":"Layout Algorithms","title":"Parameters","text":"Parameter Type Default Description\nxmin Float64 0.0 Minimum x coordinate\nxmax Float64 1.0 Maximum x coordinate\nymin Float64 0.0 Minimum y coordinate\nymax Float64 1.0 Maximum y coordinate","category":"section"},{"location":"guide/layout/#When-to-Use-Random-Layout","page":"Layout Algorithms","title":"When to Use Random Layout","text":"Quick exploration: Get an immediate (if uninformative) view\nStress testing: Verify that visualization code handles arbitrary positions\nStarting point: Initialize positions before applying a force-directed refinement\nBaseline comparison: Measure how much structure a force-directed layout reveals","category":"section"},{"location":"guide/layout/#Choosing-an-Algorithm","page":"Layout Algorithms","title":"Choosing an Algorithm","text":"","category":"section"},{"location":"guide/layout/#Decision-Guide","page":"Layout Algorithms","title":"Decision Guide","text":"Is your network small (<50 vertices)?\n├── Yes: Do you care about graph distances?\n│   ├── Yes → KKLayout\n│   └── No → FRLayout\n└── No: Is speed critical?\n    ├── Yes → CircleLayout or RandomLayout\n    └── No → FRLayout (with reduced iterations if needed)","category":"section"},{"location":"guide/layout/#Visual-Comparison","page":"Layout Algorithms","title":"Visual Comparison","text":"Consider a network with community structure:\n\nAlgorithm Reveals Structure? Stable? Speed\nFR Yes – communities cluster With anchoring Medium\nKK Yes – distances are meaningful High Slow\nCircle No – all vertices equidistant Perfect Fast\nRandom No – positions are meaningless None Fast","category":"section"},{"location":"guide/layout/#Combining-Algorithms","page":"Layout Algorithms","title":"Combining Algorithms","text":"You can use different algorithms at different stages:\n\n# Use circle layout for the first frame (stable starting point)\n# Then switch to FR for the rest\nfirst_pos = compute_slice_layout(dnet, 0.0; algorithm=CircleLayout())\n\n# Use FR with anchoring for subsequent frames\ntimes = collect(10.0:10.0:100.0)\npositions = [first_pos]\nfor t in times\n    snapshot = network_extract(dnet, t)\n    pos = compute_layout_anchored(snapshot, FRLayout(), positions[end])\n    push!(positions, pos)\nend","category":"section"},{"location":"guide/layout/#Layout-for-Dynamic-Networks","page":"Layout Algorithms","title":"Layout for Dynamic Networks","text":"","category":"section"},{"location":"guide/layout/#Anchored-Layout-Computation","page":"Layout Algorithms","title":"Anchored Layout Computation","text":"When computing layouts for animation, NDTV.jl uses the previous frame's positions as starting points. This is the key to smooth animation:\n\n# Automatically uses anchoring\nlayout = layout_sequence(dnet, times; anchor=true)\n\nThe anchored computation:\n\nCopies positions from the previous frame\nNew vertices get random positions\nRuns the layout algorithm with reduced temperature\nPositions gradually adapt to structural changes","category":"section"},{"location":"guide/layout/#Handling-Vertex-Appearance-and-Disappearance","page":"Layout Algorithms","title":"Handling Vertex Appearance and Disappearance","text":"When a vertex appears in a new frame:\n\nIt receives a random initial position\nThe layout algorithm positions it near its neighbors\nOver subsequent frames, it settles into a stable position\n\nWhen a vertex disappears:\n\nIts position is simply dropped from the frame\nRemaining vertices may shift slightly to fill the gap\n\nWhen a vertex reappears after a gap:\n\nIt gets a new random position (its old position is not remembered)\nIt settles near its current neighbors, which may differ from before","category":"section"},{"location":"guide/layout/#Advanced-Topics","page":"Layout Algorithms","title":"Advanced Topics","text":"","category":"section"},{"location":"guide/layout/#Reproducible-Layouts","page":"Layout Algorithms","title":"Reproducible Layouts","text":"Force-directed layouts use random initialization. For reproducible results, seed the random number generator:\n\nusing Random\nRandom.seed!(42)\n\nlayout = render_animation(dnet; n_frames=100, algorithm=FRLayout())","category":"section"},{"location":"guide/layout/#Layout-Bounds","page":"Layout Algorithms","title":"Layout Bounds","text":"Every DynamicLayout has a bounds field computed from all vertex positions across all frames:\n\nlayout = render_animation(dnet; n_frames=100)\nxmin, xmax, ymin, ymax = layout.bounds\n\n# Use for consistent scaling across frames\nwidth = xmax - xmin\nheight = ymax - ymin","category":"section"},{"location":"guide/layout/#Custom-Layout-Functions","page":"Layout Algorithms","title":"Custom Layout Functions","text":"You can use compute_layout directly on a static Network:\n\nusing Network\n\n# Create a static network\nnet = Network(5; directed=false)\nadd_edge!(net, 1, 2)\nadd_edge!(net, 2, 3)\nadd_edge!(net, 3, 4)\n\n# Compute layout\npositions = compute_layout(net, FRLayout(iterations=200))","category":"section"},{"location":"#NDTV.jl","page":"Home","title":"NDTV.jl","text":"Network Dynamic Temporal Visualization for Julia\n\nA Julia package for visualizing dynamic networks through animations, timeline plots, filmstrip displays, and layout algorithms for time-varying network data.","category":"section"},{"location":"#Overview","page":"Home","title":"Overview","text":"NDTV.jl provides tools for computing and displaying the evolution of networks over time. It computes smooth layout transitions, generates timeline visualizations, and exports animations in multiple formats. NDTV.jl works with dynamic networks from NetworkDynamic.jl.\n\nNDTV.jl is a port of the R ndtv package from the StatNet collection.","category":"section"},{"location":"#What-is-Dynamic-Network-Visualization?","page":"Home","title":"What is Dynamic Network Visualization?","text":"Dynamic networks change over time – vertices and edges appear and disappear. Visualizing these changes requires:\n\nTime 0        Time 25       Time 50       Time 75       Time 100\n  A--B         A--B          A  B           A--B--C       A--B--C\n  |            |  |          |              |     |           |\n  C            C--D          C--D           D     E       D--E\n\nNDTV.jl computes layouts for each time point and provides smooth transitions between them.","category":"section"},{"location":"#Key-Concepts","page":"Home","title":"Key Concepts","text":"Concept Description\nDynamicLayout Vertex positions across multiple time points\nInterpolatedLayout Smooth position interpolation between time points\nLayout Algorithm Method for positioning vertices (FR, KK, circle, random)\nTimeline Plot ASCII visualization of vertex and edge activity spells\nFilmstrip Multiple network snapshots side by side\nAnimation Continuous layout transitions with export support","category":"section"},{"location":"#Applications","page":"Home","title":"Applications","text":"NDTV.jl is designed for:\n\nEpidemiology: Visualizing disease transmission through a contact network\nCommunication analysis: Showing how interaction patterns evolve\nOrganizational studies: Displaying changes in collaboration structures\nSocial media: Animating the growth and evolution of online networks\nEcological studies: Visualizing animal social network dynamics","category":"section"},{"location":"#Features","page":"Home","title":"Features","text":"Animation rendering: Compute smooth layout transitions across time\nLayout algorithms: Fruchterman-Reingold, Kamada-Kawai, circular, and random layouts\nTimeline visualization: ASCII timeline plots showing vertex and edge activity\nProximity timeline: Ego-centric activity views\nTransmission timeline: Visualize diffusion and contagion events\nFilmstrip: Multiple time-point snapshots\nExport: HTML, video (FFmpeg), and GIF (ImageMagick) output","category":"section"},{"location":"#Installation","page":"Home","title":"Installation","text":"using Pkg\nPkg.add(url=\"https://github.com/Statistical-network-analysis-with-Julia/NDTV.jl\")\n\nOr for development:\n\nusing Pkg\nPkg.develop(path=\"/path/to/NDTV.jl\")","category":"section"},{"location":"#Quick-Start","page":"Home","title":"Quick Start","text":"using NetworkDynamic\nusing NDTV\n\n# Create a dynamic network\ndnet = DynamicNetwork(10; observation_start=0.0, observation_end=100.0)\n\n# Activate vertices\nfor i in 1:10\n    activate!(dnet, 0.0, 100.0; vertex=i)\nend\n\n# Add edge activity spells\nactivate!(dnet, 0.0, 50.0; edge=(1, 2))\nactivate!(dnet, 20.0, 80.0; edge=(2, 3))\nactivate!(dnet, 40.0, 100.0; edge=(3, 4))\n\n# Compute animation layout\nlayout = render_animation(dnet; n_frames=50)\n\n# Show timeline\ntimeline_plot(dnet)\n\n# Export to HTML\nexport_html(layout, \"network_animation.html\")","category":"section"},{"location":"#Visualization-Types","page":"Home","title":"Visualization Types","text":"Type Function Description\nAnimation render_animation Smooth layout transitions across time\nTimeline timeline_plot ASCII activity timeline\nProximity proximity_timeline Ego-centric activity view\nTransmission transmissionTimeline Diffusion event visualization\nFilmstrip filmstrip Multiple snapshots at specified times\nSingle snapshot compute_slice_layout Layout at a single time point","category":"section"},{"location":"#Documentation","page":"Home","title":"Documentation","text":"Pages = [\n    \"getting_started.md\",\n    \"guide/animation.md\",\n    \"guide/layout.md\",\n    \"guide/export.md\",\n    \"api/types.md\",\n    \"api/layout.md\",\n    \"api/export.md\",\n]\nDepth = 2","category":"section"},{"location":"#Theoretical-Background","page":"Home","title":"Theoretical Background","text":"","category":"section"},{"location":"#Force-Directed-Layout","page":"Home","title":"Force-Directed Layout","text":"The Fruchterman-Reingold algorithm treats the network as a physical system:\n\nRepulsive forces push all vertex pairs apart: f_r(d) = k^2  d\nAttractive forces pull connected vertices together: f_a(d) = d^2  k\nSimulated annealing gradually reduces the temperature to settle into a stable layout\n\nWhere k = sqrttextarea  n is the optimal spacing and d is the distance between vertices.","category":"section"},{"location":"#Dynamic-Layout-Stability","page":"Home","title":"Dynamic Layout Stability","text":"For dynamic networks, NDTV.jl uses anchored layouts: each frame uses the previous frame's positions as starting points. This produces smooth transitions where:\n\nPersistent vertices maintain stable positions\nNew vertices appear near their neighbors\nLayout changes are gradual rather than abrupt","category":"section"},{"location":"#Interpolation","page":"Home","title":"Interpolation","text":"Between computed layout frames, positions are interpolated:\n\nLinear: p(t) = p_1 + alpha cdot (p_2 - p_1)\nEase: Smooth acceleration and deceleration using cubic easing","category":"section"},{"location":"#References","page":"Home","title":"References","text":"Bender-deMoll, S., Morris, M., Moody, J. (2008). Prototype packages for managing and animating longitudinal network data: dynamicnetwork and rSoNIA. Journal of Statistical Software, 24(7), 1-36.\nFruchterman, T.M.J., Reingold, E.M. (1991). Graph drawing by force-directed placement. Software: Practice and Experience, 21(11), 1129-1164.\nKamada, T., Kawai, S. (1989). An algorithm for drawing general undirected graphs. Information Processing Letters, 31(1), 7-15.\nMoody, J., McFarland, D., Bender-deMoll, S. (2005). Dynamic network visualization. American Journal of Sociology, 110(4), 1206-1241.","category":"section"},{"location":"guide/animation/#Animation-Layout","page":"Animation Layout","title":"Animation Layout","text":"This guide covers how NDTV.jl computes smooth layout transitions for animating dynamic networks.","category":"section"},{"location":"guide/animation/#Overview","page":"Animation Layout","title":"Overview","text":"Dynamic network animation requires computing vertex positions at many time points so that the network appears to evolve smoothly. NDTV.jl achieves this through:\n\nNetwork slicing – extracting the active subnetwork at each time point\nLayout computation – positioning vertices using force-directed or geometric algorithms\nAnchoring – using the previous frame's positions as starting points for stability\nInterpolation – smoothing transitions between computed frames","category":"section"},{"location":"guide/animation/#The-Animation-Pipeline","page":"Animation Layout","title":"The Animation Pipeline","text":"DynamicNetwork\n      │\n      ▼\n  ┌───────────┐     ┌──────────────┐     ┌────────────────┐\n  │ Time slice │────▶│ Layout compute│────▶│ DynamicLayout  │\n  │  at t_1    │     │  (anchored)  │     │  positions[1]  │\n  └───────────┘     └──────────────┘     └────────────────┘\n                          │ anchor\n                          ▼\n  ┌───────────┐     ┌──────────────┐     ┌────────────────┐\n  │ Time slice │────▶│ Layout compute│────▶│ DynamicLayout  │\n  │  at t_2    │     │  (anchored)  │     │  positions[2]  │\n  └───────────┘     └──────────────┘     └────────────────┘\n                          │ anchor\n                          ▼\n                         ...\n                          │\n                          ▼\n                  ┌────────────────────┐\n                  │ InterpolatedLayout │\n                  │  (optional smooth) │\n                  └────────────────────┘","category":"section"},{"location":"guide/animation/#Computing-an-Animation","page":"Animation Layout","title":"Computing an Animation","text":"","category":"section"},{"location":"guide/animation/#Using-render_animation","page":"Animation Layout","title":"Using render_animation","text":"The simplest way to create an animation is with render_animation:\n\nusing NetworkDynamic\nusing NDTV\n\n# Create a dynamic network\ndnet = DynamicNetwork(10; observation_start=0.0, observation_end=100.0)\nfor i in 1:10\n    activate!(dnet, 0.0, 100.0; vertex=i)\nend\nactivate!(dnet, 0.0, 50.0; edge=(1, 2))\nactivate!(dnet, 20.0, 80.0; edge=(2, 3))\nactivate!(dnet, 40.0, 100.0; edge=(3, 4))\n\n# Compute animation with 100 frames\nlayout = render_animation(dnet;\n    algorithm=FRLayout(),\n    n_frames=100,\n    interpolation=:linear\n)\n\nParameters:\n\nParameter Type Default Description\nalgorithm Layout type FRLayout() Layout algorithm to use\nn_frames Int 100 Number of frames to compute\ninterpolation Symbol :linear Interpolation mode (:linear, :ease, :none)","category":"section"},{"location":"guide/animation/#Frame-Computation","page":"Animation Layout","title":"Frame Computation","text":"render_animation divides the observation period into evenly-spaced time points and computes a layout at each one:\n\n# With n_frames=5 over [0, 100]:\n# Times: [0.0, 25.0, 50.0, 75.0, 100.0]\n# At each time, the active subnetwork is extracted and laid out\n\nThe observation period is taken from the DynamicNetwork's observation_period field:\n\nstart_time, end_time = dnet.observation_period\n# Frames are evenly spaced from start_time to end_time","category":"section"},{"location":"guide/animation/#Layout-Sequences","page":"Animation Layout","title":"Layout Sequences","text":"For more control over which time points to compute, use layout_sequence:\n\n# Compute layouts at specific time points\ntimes = [0.0, 10.0, 25.0, 50.0, 75.0, 100.0]\nlayout = layout_sequence(dnet, times;\n    algorithm=FRLayout(),\n    anchor=true\n)\n\nThis is useful when you want:\n\nNon-uniform time spacing (e.g., more detail during active periods)\nLayouts only at specific events of interest\nCustom time grids that match your data","category":"section"},{"location":"guide/animation/#Anchored-vs.-Independent-Layouts","page":"Animation Layout","title":"Anchored vs. Independent Layouts","text":"The anchor parameter controls layout stability:\n\nAnchored (default, anchor=true):\n\nEach frame starts from the previous frame's vertex positions\nUses half the normal iterations (since starting positions are good)\nProduces smooth, stable transitions\nPersistent vertices barely move between frames\n\nIndependent (anchor=false):\n\nEach frame is computed from scratch with random initial positions\nFull iteration count\nFrames may show dramatically different arrangements\nUseful for comparing structural properties without positional bias\n\n# Anchored -- smooth transitions\nlayout_smooth = layout_sequence(dnet, times; anchor=true)\n\n# Independent -- each frame computed fresh\nlayout_fresh = layout_sequence(dnet, times; anchor=false)","category":"section"},{"location":"guide/animation/#How-Anchoring-Works","page":"Animation Layout","title":"How Anchoring Works","text":"When anchoring is enabled, the algorithm:\n\nChecks which vertices existed in the previous frame\nCopies their positions as starting points\nNew vertices (not in the previous frame) get random initial positions\nRuns the layout algorithm with reduced temperature/iterations\n\nThis means:\n\nVertices that persist between frames drift gradually to accommodate new structure\nNew vertices settle near their neighbors naturally\nThe overall layout remains recognizable across frames","category":"section"},{"location":"guide/animation/#Single-Frame-Layout","page":"Animation Layout","title":"Single-Frame Layout","text":"For a layout at a single time point, use compute_slice_layout:\n\n# Get vertex positions at t=50\npositions = compute_slice_layout(dnet, 50.0; algorithm=FRLayout())\n# Returns Dict{vertex_id => (x, y)}\n\nfor (v, (x, y)) in positions\n    println(\"Vertex $v: ($x, $y)\")\nend\n\nThis extracts the active subnetwork at the given time and applies the layout algorithm once.","category":"section"},{"location":"guide/animation/#Interpolated-Layouts","page":"Animation Layout","title":"Interpolated Layouts","text":"For smoother animation between computed frames, wrap a DynamicLayout in an InterpolatedLayout:\n\n# Compute base layout at a few time points\nbase = layout_sequence(dnet, collect(0.0:20.0:100.0);\n    algorithm=FRLayout()\n)\n\n# Create interpolated layout\ninterp = InterpolatedLayout(base; interpolation=:ease)\n\n# Query position at any time (not just computed times)\npos = get_position(interp, 1, 35.0)\nprintln(\"Vertex 1 at t=35: ($(pos[1]), $(pos[2]))\")","category":"section"},{"location":"guide/animation/#Interpolation-Modes","page":"Animation Layout","title":"Interpolation Modes","text":"Linear interpolation (:linear)\n\nPositions change at constant velocity between frames:\n\np(t) = p_1 + alpha cdot (p_2 - p_1)\n\nwhere alpha = (t - t_1)  (t_2 - t_1) is the fractional position between frames.\n\nEase interpolation (:ease)\n\nUses cubic ease-in-out for smooth acceleration and deceleration:\n\nalpha_textease = begincases\n2alpha^2  textif  alpha  05 \n1 - frac(-2alpha + 2)^22  textotherwise\nendcases\n\nThis produces natural-looking motion where vertices slow down as they approach their target positions.\n\nMode Visual Effect Use Case\n:linear Constant speed Technical analysis, precise tracking\n:ease Smooth start/stop Presentations, publications\n:none No interpolation (discrete) Frame-by-frame inspection","category":"section"},{"location":"guide/animation/#Querying-Interpolated-Positions","page":"Animation Layout","title":"Querying Interpolated Positions","text":"The get_position function returns a vertex's position at any time:\n\ninterp = InterpolatedLayout(base; interpolation=:ease)\n\n# Get position at exact frame time (no interpolation needed)\npos_exact = get_position(interp, 1, 20.0)\n\n# Get position between frames (interpolated)\npos_between = get_position(interp, 1, 35.0)\n\n# Before first frame -- returns first frame position\npos_before = get_position(interp, 1, -5.0)\n\n# After last frame -- returns last frame position\npos_after = get_position(interp, 1, 200.0)","category":"section"},{"location":"guide/animation/#Working-with-DynamicLayout","page":"Animation Layout","title":"Working with DynamicLayout","text":"The DynamicLayout type stores computed positions:\n\nlayout = render_animation(dnet; n_frames=50)\n\n# Number of frames\nlength(layout)  # 50\n\n# Access positions at a specific frame\nframe_10 = layout[10]  # Dict{T, Tuple{Float64, Float64}}\n\n# Time points\nlayout.times  # Vector{Float64} of length 50\n\n# Bounding box for all frames\nxmin, xmax, ymin, ymax = layout.bounds","category":"section"},{"location":"guide/animation/#Extracting-Frame-Data","page":"Animation Layout","title":"Extracting Frame Data","text":"# Iterate over all frames\nfor (i, t) in enumerate(layout.times)\n    positions = layout[i]\n    n_vertices = length(positions)\n    println(\"Frame $i (t=$t): $n_vertices vertices positioned\")\nend\n\n# Get all positions for a single vertex across time\nvertex_trajectory = [(t, layout[i][1]) for (i, t) in enumerate(layout.times)\n                     if haskey(layout[i], 1)]","category":"section"},{"location":"guide/animation/#Timeline-Visualization","page":"Animation Layout","title":"Timeline Visualization","text":"","category":"section"},{"location":"guide/animation/#Timeline-Plot","page":"Animation Layout","title":"Timeline Plot","text":"timeline_plot creates an ASCII visualization of vertex and edge activity:\n\ntimeline_plot(dnet; width=60)\n\nThe output uses ─ for vertex activity and ═ for edge activity, scaled to the specified width. This gives an immediate overview of when network elements are active.","category":"section"},{"location":"guide/animation/#Proximity-Timeline","page":"Animation Layout","title":"Proximity Timeline","text":"proximity_timeline shows the activity of edges connected to a specific vertex:\n\n# Show all edges involving vertex 3\nproximity_timeline(dnet, 3; width=60)\n\nThis is useful for understanding a vertex's local network dynamics – when its connections appear and disappear.","category":"section"},{"location":"guide/animation/#Transmission-Timeline","page":"Animation Layout","title":"Transmission Timeline","text":"transmissionTimeline visualizes discrete transmission events (e.g., disease spread, information diffusion):\n\ntransmissions = [\n    (1, 2, 5.0),\n    (2, 3, 12.0),\n    (2, 4, 15.0),\n]\n\ntransmissionTimeline(dnet, transmissions; width=60)\n\nEach transmission is shown as a * at its time position on the timeline.","category":"section"},{"location":"guide/animation/#Timeline-Data","page":"Animation Layout","title":"Timeline Data","text":"timeline_data extracts raw activity data for custom plotting:\n\ndata = timeline_data(dnet)\n\n# Vertex activity spells\nfor v in data.vertices\n    println(\"Vertex $(v.vertex): active $(v.onset) to $(v.terminus)\")\nend\n\n# Edge activity spells\nfor e in data.edges\n    println(\"Edge $(e.source)→$(e.target): active $(e.onset) to $(e.terminus)\")\nend","category":"section"},{"location":"guide/animation/#Filmstrip","page":"Animation Layout","title":"Filmstrip","text":"","category":"section"},{"location":"guide/animation/#Basic-Filmstrip","page":"Animation Layout","title":"Basic Filmstrip","text":"filmstrip generates layout data for multiple time-point snapshots:\n\ntimes = [0.0, 25.0, 50.0, 75.0, 100.0]\nframes = filmstrip(dnet, times; algorithm=FRLayout())\n\nfor frame in frames\n    println(\"t=$(frame.time): $(frame.n_vertices)v, $(frame.n_edges)e\")\n    println(\"  Positions: \", frame.positions)\nend","category":"section"},{"location":"guide/animation/#Slice-Layout","page":"Animation Layout","title":"Slice Layout","text":"slice_layout generates evenly-spaced slices over an interval:\n\n# 5 snapshots between t=10 and t=90\nframes = slice_layout(dnet, 10.0, 90.0; n_slices=5, algorithm=FRLayout())\n# Computes at t = 10.0, 30.0, 50.0, 70.0, 90.0","category":"section"},{"location":"guide/animation/#Performance-Considerations","page":"Animation Layout","title":"Performance Considerations","text":"","category":"section"},{"location":"guide/animation/#Number-of-Frames","page":"Animation Layout","title":"Number of Frames","text":"More frames produce smoother animation but take longer to compute:\n\nFrames Quality Compute Time (relative)\n25 Choppy 1x\n50 Acceptable 2x\n100 Smooth 4x\n200 Very smooth 8x\n\nFor large networks (>100 vertices), start with fewer frames and increase as needed.","category":"section"},{"location":"guide/animation/#Layout-Algorithm-Choice","page":"Animation Layout","title":"Layout Algorithm Choice","text":"FRLayout: O(n^2) per iteration due to pairwise repulsion. Good for networks up to ~500 vertices.\nKKLayout: More expensive per iteration but may converge faster. Best for small networks.\nCircleLayout: O(n) – fast but ignores network structure.\nRandomLayout: O(n) – fastest, but no structural information.","category":"section"},{"location":"guide/animation/#Reducing-Computation","page":"Animation Layout","title":"Reducing Computation","text":"# Fewer iterations for faster (rougher) layouts\nfast_alg = FRLayout(iterations=30, cooling=0.9)\n\n# Compute fewer frames\nlayout = render_animation(dnet; n_frames=25, algorithm=fast_alg)","category":"section"}]
}
